import React, { useState } from "react";

const API_BASE = "http://localhost:8000";

const STAGES = [
  "Preparing protein",
  "Preparing ligands",
  "Running docking",
  "Filtering hits",
  "Generating fingerprints",
  "Clustering molecules",
  "Selecting diverse hits",
];

function RunPipeline({ onPipelineDone, onStatus }) {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [maxLigands, setMaxLigands] = useState(500);
  const [currentStage, setCurrentStage] = useState("");

  const setStage = (stage) => {
    setCurrentStage(stage);
    onStatus(stage);
  };

  const runVirtualScreening = async () => {
    try {
      setLoading(true);
      setError("");
      setCurrentStage("");

      setStage("Preparing protein");
      setStage("Preparing ligands");
      setStage("Running docking");
      const dockUrl = `${API_BASE}/run-docking?max_ligands=${maxLigands}`;
      let response = await fetch(dockUrl, { method: "POST" });
      if (!response.ok) throw new Error((await response.json()).detail || "Docking stage failed");

      setStage("Filtering hits");
      response = await fetch(`${API_BASE}/filter-hits`, { method: "POST" });
      if (!response.ok) throw new Error((await response.json()).detail || "Filtering stage failed");

      setStage("Generating fingerprints");
      setStage("Clustering molecules");
      setStage("Selecting diverse hits");
      response = await fetch(`${API_BASE}/run-clustering`, { method: "POST" });
      if (!response.ok) throw new Error((await response.json()).detail || "Clustering stage failed");

      setStage("Pipeline complete");
      onPipelineDone();
    } catch (err) {
      setError(err.message);
      onStatus(`Pipeline error: ${err.message}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <section className="panel">
      <h2>Run Pipeline</h2>

      <label className="ligand-cap-label">
        Molecules to screen
        <input
          type="number"
          min="10"
          max="71930"
          value={maxLigands}
          onChange={(e) => setMaxLigands(Number(e.target.value))}
          disabled={loading}
          className="ligand-cap-input"
        />
      </label>
      <p className="cap-hint">
        {maxLigands <= 1000
          ? `Quick test — ~${Math.round(maxLigands * 0.12)} min estimated`
          : maxLigands <= 10000
          ? `Medium run — could take 1–3 hrs`
          : `Full dataset — may take several hours`}
      </p>

      <button onClick={runVirtualScreening} disabled={loading} className="run-button">
        {loading ? `Running\u2026 (${currentStage})` : "Run Virtual Screening"}
      </button>

      {loading && (
        <div className="stages-list">
          {STAGES.map((s) => (
            <div
              key={s}
              className={
                currentStage === s
                  ? "stage stage-active"
                  : STAGES.indexOf(s) < STAGES.indexOf(currentStage)
                  ? "stage stage-done"
                  : "stage stage-pending"
              }
            >
              {STAGES.indexOf(s) < STAGES.indexOf(currentStage) ? "✓ " : currentStage === s ? "⏳ " : "○ "}
              {s}
            </div>
          ))}
        </div>
      )}

      {error ? <p className="error">{error}</p> : null}
    </section>
  );
}

export default RunPipeline;
